mapper.select:
/* RwdMgmtMapper.chkDupRwdProd */
SELECT	COUNT(RWD_PROD_CD)
FROM	MSP_RWD_MST A
WHERE	RWD_PROD_CD = #{rwdProdCd}

mapper.insert:
/* RwdMgmtMapper.regRwdMst */
INSERT
INTO	MSP_RWD_MST (
		  RWD_PROD_CD
		, RWD_PRD
		, USE_YN
		, REGST_ID
		, REGST_DTTM
		, RVISN_ID
		, RVISN_DTTM
)
VALUES (
		  #{rwdProdCd}
		, #{rwdPrd}
		, NVL(#{useYn}, 'Y')
		, #{sessionUserId}
		, SYSDATE
		, #{sessionUserId}
		, SYSDATE
)

mapper.update:
/* RwdMgmtMapper.updRwdMst */
UPDATE MSP_RWD_MST
SET		  USE_YN = #{useYn}
		, RWD_PRD = #{rwdPrd}
		, RVISN_ID = #{sessionUserId}
		, RVISN_DTTM = SYSDATE
WHERE	RWD_PROD_CD = #{rwdProdCd}

mapper.select:
/* RwdMgmtMapper.getRwdMstList */ SELECT DISTINCT A.RATE_CD AS rwdProdCd , A.RATE_NM AS rwdProdNm , A.BASE_AMT AS baseAmt , FN_GET_CODENM('CMN0259', C.RWD_PRD) AS rwdPrd , C.USE_YN AS useYn , FN_GET_USRNM(C.REGST_ID) AS regstId , TO_CHAR(C.REGST_DTTM, 'YYYYMMDDHH24MISS') AS regstDttm , FN_GET_USRNM(C.RVISN_ID) AS rvisnId , TO_CHAR(C.RVISN_DTTM, 'YYYYMMDDHH24MISS') AS rvisnDttm , B.ETC6 AS ordrNo FROM MSP_RATE_MST A , CMN_GRP_CD_MST B , MSP_RWD_MST C , MSP_RWD_REL D WHERE A.RATE_CD = B.CD_VAL AND B.GRP_ID = 'CMN0258' AND A.RATE_CD = C.RWD_PROD_CD AND C.RWD_PROD_CD = D.RWD_PROD_CD(+)
AND D.RPRS_PRDT_ID = #{rprsPrdtId}
AND D.APPL_YN = #{applYn}
AND C.USE_YN = #{useYn}
AND #{trtmDt} BETWEEN A.APPL_STRT_DT AND A.APPL_END_DT ORDER BY B.ETC6

mapper.insert:
/* RwdMgmtMapper.regRwdRel */
INSERT
INTO	MSP_RWD_REL (
		  RWD_PROD_CD
		, RPRS_PRDT_ID
		, APPL_YN
		, REGST_ID
		, REGST_DTTM
		, RVISN_ID
		, RVISN_DTTM
)
VALUES (
		  #{rwdProdCd}
		, #{rprsPrdtId}
		, DECODE(#{applYn}, 1, 'Y', 0, 'N', NVL(#{applYn}, 'Y'))
		, #{sessionUserId}
		, SYSDATE
		, #{sessionUserId}
		, SYSDATE
)

mapper.select:
/* RwdMgmtMapper.chkDupRwdPrdt */
SELECT 	COUNT(RWD_PROD_CD)
FROM 	MSP_RWD_REL
WHERE 	RWD_PROD_CD =  #{rwdProdCd}
AND 	RPRS_PRDT_ID = #{rprsPrdtId}

mapper.sql:
SELECT C.RWD_PROD_CD AS rwdProdCd , D.RATE_NM AS rwdProdNm , B.MNFCT_NM AS mnfctNm , A.RPRS_PRDT_ID AS rprsPrdtId , A.PRDT_CODE AS prdtCode , A.PRDT_NM AS prdtNm , DECODE(C.APPL_YN, 'Y', 1, 'N', 0) AS applYn , C.APPL_YN AS applYnNm , FN_GET_USRNM(C.REGST_ID) AS regstId , TO_CHAR(C.REGST_DTTM, 'YYYYMMDDHH24MISS') AS regstDttm , FN_GET_USRNM(C.RVISN_ID) AS rvisnId , TO_CHAR(C.RVISN_DTTM, 'YYYYMMDDHH24MISS') AS rvisnDttm FROM CMN_INTM_MDL A , ORG_MNFCT_MST B , MSP_RWD_REL C , MSP_RATE_MST D , CMN_GRP_CD_MST E , MSP_RWD_MST F WHERE A.RPRS_YN ='Y' AND A.MNFCT_ID = B.MNFCT_ID AND C.RPRS_PRDT_ID = A.RPRS_PRDT_ID AND C.RWD_PROD_CD = D.RATE_CD AND C.RWD_PROD_CD = E.CD_VAL AND E.GRP_ID = 'CMN0258' AND C.RWD_PROD_CD = F.RWD_PROD_CD
AND C.RWD_PROD_CD = #{rwdProdCd}
AND C.APPL_YN = #{applYn}
AND A.RPRS_PRDT_ID = #{rprsPrdtId}
AND UPPER(A.PRDT_NM) LIKE '%'|| UPPER(#{prdtNm}) ||'%'
AND F.USE_YN = #{useYn}
AND #{trtmDt} BETWEEN D.APPL_STRT_DT AND D.APPL_END_DT ORDER BY E.ETC6, A.MNFCT_ID, A.PRDT_CODE, A.PRDT_NM

mapper.update:
/* RwdMgmtMapper.updRwdRel */
UPDATE 	MSP_RWD_REL
SET		APPL_YN = DECODE(#{applYn}, 1, 'Y', 0, 'N', NVL(#{applYn}, 'Y'))
		, RVISN_ID = #{sessionUserId}
		, RVISN_DTTM = SYSDATE
WHERE	RWD_PROD_CD = #{rwdProdCd}
AND 	RPRS_PRDT_ID = #{rprsPrdtId}

mapper.select:
/* RwdMgmtMapper.getRwdCombo */ SELECT A.RWD_PROD_CD AS value , C.RATE_NM AS text FROM MSP_RWD_MST A , CMN_GRP_CD_MST B , MSP_RATE_MST C WHERE A.RWD_PROD_CD = B.CD_VAL AND B.GRP_ID = 'CMN0258' AND A.RWD_PROD_CD = C.RATE_CD
AND A.USE_YN = #{useYn}
ORDER BY ETC6
